"""5.3 ***Feature Engineering***

Create new useful features:

*   Price_per_SqFt (if not available)
*   Age_of_Property = Current Year – Year_Built
*   Investment Score (optional)


5.4 ***Encode Categorical Data***
*   City, Property_Type, Furnished_Status
"""

pd.get_dummies(df, drop_first=True)

"""5.5 ***Feature Scaling***"""

from sklearn.preprocessing import StandardScaler

"""6. **Create Target Variables**

*Regression Target*
*   Future Price after 5 years
"""

r = 0.08   # 8% growth rate
t = 5      # 5 years

df['Future_Price'] = df['Price_in_Lakhs'] * (1 + r) ** t

"""*Classification Target*

Create Good Investment label:
"""

df['Good_Investment'] = df['Price_in_Lakhs'] < df['Price_in_Lakhs'].median()

